func:
// Discord Python 上線通知
// =========================

msg.headers = {
    "Content-Type": "application/json"
};

msg.url = "https://discord.com/api/webhooks/1507070766271959061/bAa1Pf55ixg0bJmqeoJTQVdPt2ScMyITxYr4ukHof8IfBUC6hCaQqysnqkn8paCXQcjO";

// =========================
// IP
// =========================
let ip =
    msg.payload?.current?.system?.ip
    || "未知IP";

// 保存 IP
flow.set(
    "python_ip",
    ip
);

// =========================
// Discord Payload
// =========================
msg.payload = {

    username:
        "Cat Health Monitor",

    embeds: [

        {

            title:
                "🟢 Python AI 已上線",

            description:
                `偵測到 Python 推論系統啟動`,

            color:
                65280,

            fields: [

                {
                    name: "Python IP",
                    value: String(ip),
                    inline: false
                }

            ],

            footer: {

                text:
                    new Date()
                        .toLocaleString()

            }

        }

    ]
};

return msg;

let ip = msg.payload && msg.payload.ip ? msg.payload.ip : (flow.get("python_ip") || null);
if (ip) {
    flow.set("python_ip", ip);
}
const streamUrl = ip ? `http://${ip}:5000/stream` : "";
msg.payload = {
current: {
behavior: -1,
text: "Python online",
emoji: "🐱",
timestamp: new Date().toLocaleTimeString(),
system: {
    ip: ip,
    stream_url: streamUrl
}
},
activity_score: 0,
today_stats: {
walk:0, walk_time:0, scratch:0, scratch_time:0,
lick:0, lick_time:0, shake:0, shake_time:0,
active_time:0, rest_time:0
},
behavior_log: [],
alerts: []
};
msg.stream_url = streamUrl;
node.warn("python_online received IP: " + (ip || 'null'));
return msg;
